        assert!(sm.can_transition(ResourcePermissionTransition::AutoExpire));
        let result = sm.transition(ResourcePermissionTransition::AutoExpire);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), ResourcePermissionState::Expired);
